img_count = 0
for city_id, img_url in city_images.items():
    if city_id in data:
        data[city_id]['image'] = img_url
        img_count += 1

print(f"\n✅ 图片更新: {img_count}个城市")

# 写回文件
new_content = 'var CITY_DATABASE = ' + json.dumps(data, ensure_ascii=False, indent=2) + ' ;'
with open('data_enhanced.js', 'w', encoding='utf-8') as f:
    f.write(new_content)

# 验证
print(f"\n=== 最终验证 ===")
start2 = new_content.find('var CITY_DATABASE = ')
d2 = json.loads(new_content[start2 + len('var CITY_DATABASE = '):].rstrip(' ;'))
print(f"城市数: {len(d2)}")
for field in ['emergency', 'festivals', 'customs', 'foodSafety', 'diseasePrevention', 'transportation', 'hospitals', 'embassies', 'safetyApps', 'selfDefense']:
    cnt = sum(1 for c in d2.values() if c.get(field))
    print(f"  {field}: {cnt}/{len(d2)}")

good_hosp = sum(1 for c in d2.values() if c.get('hospitals') and len(c['hospitals']) >= 2)
print(f"  有2+医院: {good_hosp}个")
img_unique = len(set(c.get('image','') for c in d2.values()))
print(f"  唯一图片: {img_unique}种")

print(f"\n✅ 所有修复完成！")
